```class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        int res = 0, mod = 1e9 + 7;
        for (char c : s) {
            res = (res + nums[c - 'a']) % mod;
        }
        res = (res * (t % mod)) % mod;
        return res;
    }
};
